REQUIRED=("id", "name", "email", "age")
def validate_rows(rows):
    for row in rows:
        for k in REQUIRED:
            if k not in row or row[k] in (None, ""): raise ValueError("missing "+k)
        # Add optional age column validation when present
        if "age" in row and not isinstance(row["age"], int): raise ValueError("invalid age value")
    return True

